sql.where:
u.del_flag = 0

	AND u.username LIKE CONCAT('%', #{dto.username}, '%')


	AND u.real_name LIKE CONCAT('%', #{dto.realName}, '%')


	AND u.mobile LIKE CONCAT('%', #{dto.mobile}, '%')


	AND u.code = #{dto.code}


	AND u.company_id = #{dto.companyId}


	AND u.dept_id = #{dto.deptId}


	AND u.user_type = #{dto.userType}


	AND (u.code LIKE CONCAT('%', #{dto.keyword}, '%')
	     OR u.username LIKE CONCAT('%', #{dto.keyword}, '%')
	     OR u.real_name LIKE CONCAT('%', #{dto.keyword}, '%'))
